import { describe, test, expect } from 'vitest';
import {
  WORKTREE_REMOVE_RE,
  worktreeMergeVerifier,
} from '../../../pretool/bash/worktree-merge-verifier.js';
import { NOOP_CTX } from '../../../lib/context.js';

describe('worktree-merge-verifier', () => {
  describe('WORKTREE_REMOVE_RE', () => {
    test.each([
      ['git worktree remove ../feat-foo', true, '../feat-foo'],
      ['git worktree remove -f ../feat-foo', true, '../feat-foo'],
      ['git worktree remove --force ../feat-foo', true, '../feat-foo'],
      ['cd repo && git worktree remove ./wt', true, './wt'],
      ['git worktree list', false, undefined],
      ['git status', false, undefined],
      ['ls ../feat-foo', false, undefined],
    ])('command: %s', (cmd, shouldMatch, expectedPath) => {
      const m = cmd.match(WORKTREE_REMOVE_RE);
      if (shouldMatch) {
        expect(m).not.toBeNull();
        expect(m?.[2]).toBe(expectedPath);
      } else {
        expect(m).toBeNull();
      }
    });
  });

  describe('hook behavior', () => {
    test('silent for non-Bash tool', () => {
      const input = { tool_name: 'Write', session_id: 's', tool_input: {} } as never;
      const r = worktreeMergeVerifier(input, { ...NOOP_CTX, projectDir: '/tmp' });
      expect(r.hookSpecificOutput).toBeUndefined();
    });

    test('silent for non-worktree Bash command', () => {
      const input = { tool_name: 'Bash', session_id: 's', tool_input: { command: 'git status' } } as never;
      const r = worktreeMergeVerifier(input, { ...NOOP_CTX, projectDir: '/tmp' });
      expect(r.hookSpecificOutput).toBeUndefined();
    });

    test('opt-out via ORK_DISABLE_WORKTREE_VERIFIER returns silent', () => {
      const original = process.env.ORK_DISABLE_WORKTREE_VERIFIER;
      process.env.ORK_DISABLE_WORKTREE_VERIFIER = '1';
      try {
        const input = { tool_name: 'Bash', session_id: 's', tool_input: { command: 'git worktree remove ../x' } } as never;
        const r = worktreeMergeVerifier(input, { ...NOOP_CTX, projectDir: '/tmp' });
        expect(r.hookSpecificOutput).toBeUndefined();
      } finally {
        if (original === undefined) delete process.env.ORK_DISABLE_WORKTREE_VERIFIER;
        else process.env.ORK_DISABLE_WORKTREE_VERIFIER = original;
      }
    });

    test('silent when worktree not in registry (unknown path)', () => {
      // Real git call runs but /tmp is not a git repo → returns empty porcelain → null branch → silent
      const input = { tool_name: 'Bash', session_id: 's', tool_input: { command: 'git worktree remove /nonexistent' } } as never;
      const r = worktreeMergeVerifier(input, { ...NOOP_CTX, projectDir: '/tmp' });
      expect(r.hookSpecificOutput).toBeUndefined();
    });
  });
});
